import{_ as e,H as r,f as t,i}from"./chunks/framework.DLd0CbzH.js";const c=JSON.parse('{"title":"常见问题","description":"","frontmatter":{},"headers":[],"relativePath":"guide/faq.md","filePath":"guide/faq.md","lastUpdated":1780150560000}'),o={name:"guide/faq.md"};function l(h,a,n,s,d,u){return r(),t("div",null,[...a[0]||(a[0]=[i('<h1 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h1><h2 id="关于平台" tabindex="-1">关于平台 <a class="header-anchor" href="#关于平台" aria-label="Permalink to &quot;关于平台&quot;">​</a></h2><h3 id="q-ay开放平台需要注册或认证吗" tabindex="-1">Q: Ay开放平台需要注册或认证吗？ <a class="header-anchor" href="#q-ay开放平台需要注册或认证吗" aria-label="Permalink to &quot;Q: Ay开放平台需要注册或认证吗？&quot;">​</a></h3><p><strong>不需要。</strong> 正如我们承诺的“三个不”：不限制次数、不限制频率、不需认证。所有 API 开箱即用，无需 API Key 或任何鉴权。</p><h3 id="q-真的没有任何限制吗" tabindex="-1">Q: 真的没有任何限制吗？ <a class="header-anchor" href="#q-真的没有任何限制吗" aria-label="Permalink to &quot;Q: 真的没有任何限制吗？&quot;">​</a></h3><p>是的。目前所有 API 均不设调用次数和频率上限。但如果发现滥用（例如每秒数千次请求影响服务稳定性），我们可能会与您联系协商合理使用策略。</p><h3 id="q-平台会一直免费吗" tabindex="-1">Q: 平台会一直免费吗？ <a class="header-anchor" href="#q-平台会一直免费吗" aria-label="Permalink to &quot;Q: 平台会一直免费吗？&quot;">​</a></h3><p>只要不倒闭，就一直开放</p><h3 id="q-服务有哪些" tabindex="-1">Q: 服务有哪些？ <a class="header-anchor" href="#q-服务有哪些" aria-label="Permalink to &quot;Q: 服务有哪些？&quot;">​</a></h3><p>目前提供 IP 归属地、添加 QQ 好友、短链解析、文本分享，详细列表请查看 <a href="/guide/#服务列表">服务列表</a>。更多服务正在开发中。</p><hr><h2 id="关于使用" tabindex="-1">关于使用 <a class="header-anchor" href="#关于使用" aria-label="Permalink to &quot;关于使用&quot;">​</a></h2><h3 id="q-如何调用-api" tabindex="-1">Q: 如何调用 API？ <a class="header-anchor" href="#q-如何调用-api" aria-label="Permalink to &quot;Q: 如何调用 API？&quot;">​</a></h3><p>直接向 <code>https://api.undz.cn</code> 发送 HTTP 请求即可，无需添加任何认证头。示例见各接口文档和<a href="/guide/#快速开始">快速开始</a>。</p><h3 id="q-添加-qq-好友接口在-pc-端能用吗" tabindex="-1">Q: 添加 QQ 好友接口在 PC 端能用吗？ <a class="header-anchor" href="#q-添加-qq-好友接口在-pc-端能用吗" aria-label="Permalink to &quot;Q: 添加 QQ 好友接口在 PC 端能用吗？&quot;">​</a></h3><p>该接口生成的 URL Scheme 双端支持，PC 端也能用，不过因为最新版QQ政策，电脑段可能会要求您先打开QQ主程序才能够使用链接唤起添加好友页面。</p><hr><h2 id="故障排查" tabindex="-1">故障排查 <a class="header-anchor" href="#故障排查" aria-label="Permalink to &quot;故障排查&quot;">​</a></h2><h3 id="q-调用-api-返回-500-错误怎么办" tabindex="-1">Q: 调用 API 返回 <code>500</code> 错误怎么办？ <a class="header-anchor" href="#q-调用-api-返回-500-错误怎么办" aria-label="Permalink to &quot;Q: 调用 API 返回 `500` 错误怎么办？&quot;">​</a></h3><p>请稍后重试。若持续出现，请通过 <a href="https://github.com/AeYunDian/open_platform/issues/new?template=bug_report.md" target="_blank" rel="noreferrer">GitHub Issues</a> 提交 bug 报告，附上请求 URL、响应内容、发生时间。</p><h3 id="q-ip-归属地返回的城市不准确怎么办" tabindex="-1">Q: IP 归属地返回的城市不准确怎么办？ <a class="header-anchor" href="#q-ip-归属地返回的城市不准确怎么办" aria-label="Permalink to &quot;Q: IP 归属地返回的城市不准确怎么办？&quot;">​</a></h3><p>我们的数据基于 Cloudflare 的 <code>request.cf</code> 对象，可能与实际有偏差。如遇到明显错误，欢迎提交 <a href="https://github.com/AeYunDian/open_platform/issues/new?template=need_help.md" target="_blank" rel="noreferrer">Issue</a> 反馈，我们会尝试手动优化数据源。</p><h3 id="q-我发现文档与实际行为不符" tabindex="-1">Q: 我发现文档与实际行为不符？ <a class="header-anchor" href="#q-我发现文档与实际行为不符" aria-label="Permalink to &quot;Q: 我发现文档与实际行为不符？&quot;">​</a></h3><p>请使用 <a href="https://github.com/AeYunDian/open_platform/issues/new?template=bug_report.md" target="_blank" rel="noreferrer">Issue</a> 提交问题，我们会在尽快核实并修正。</p><hr><h2 id="其他问题" tabindex="-1">其他问题 <a class="header-anchor" href="#其他问题" aria-label="Permalink to &quot;其他问题&quot;">​</a></h2><h3 id="q-我想请求增加新功能-如何提交" tabindex="-1">Q: 我想请求增加新功能，如何提交？ <a class="header-anchor" href="#q-我想请求增加新功能-如何提交" aria-label="Permalink to &quot;Q: 我想请求增加新功能，如何提交？&quot;">​</a></h3><p>请使用 <a href="https://github.com/AeYunDian/open_platform/issues/new?template=feature_request.md" target="_blank" rel="noreferrer">功能请求模板</a> 描述您的需求和使用场景。</p><h3 id="q-如何联系平台维护者" tabindex="-1">Q: 如何联系平台维护者？ <a class="header-anchor" href="#q-如何联系平台维护者" aria-label="Permalink to &quot;Q: 如何联系平台维护者？&quot;">​</a></h3><ul><li>通过 GitHub <a href="https://github.com/AeYunDian/open_platform/issues" target="_blank" rel="noreferrer">Issues</a>（推荐）</li><li>发送邮件至 <a href="mailto:admin@exm.undz.cn" target="_blank" rel="noreferrer">admin@exm.undz.cn</a></li><li>通过 <a href="https://space.bilibili.com/3494370328185235" target="_blank" rel="noreferrer">BiliBili</a></li></ul><h3 id="q-平台代码开源吗" tabindex="-1">Q: 平台代码开源吗？ <a class="header-anchor" href="#q-平台代码开源吗" aria-label="Permalink to &quot;Q: 平台代码开源吗？&quot;">​</a></h3><p>大部分已开源在 <a href="https://github.com/AeYunDian/api" target="_blank" rel="noreferrer">GitHub</a>，可直接使用，欢迎 star 和贡献。</p><hr><h2 id="还没找到答案" tabindex="-1">还没找到答案？ <a class="header-anchor" href="#还没找到答案" aria-label="Permalink to &quot;还没找到答案？&quot;">​</a></h2><p>请前往 <a href="https://github.com/AeYunDian/open_platform/issues" target="_blank" rel="noreferrer">GitHub Issues</a> 选择对应的模板提问，我们会尽快回复。</p>',35)])])}const q=e(o,[["render",l]]);export{c as __pageData,q as default};
